module top_module(
	input  wire clk,

	input  wire re,
	input  wire [8:0] rdaddr,
	output reg  [7:0] dataout,

	input  wire we,
	input  wire [8:0] wraddr,
	input  wire [7:0] datain
);reg [7:0] mem[0:511]; 



	  wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge dbg_halt)
	if( re )
		dataout <= mem[rdaddr];

	always @(posedge clk)
	if( we )
		mem[wraddr] <= datain;

endmodule
